export class PagoError extends Error {}

export class PagoNetworkError extends PagoError {
  constructor(message: string) {
    super(`Pago API network error: ${message}`);
    this.name = "PagoNetworkError";
  }
}

export class PagoServerError extends PagoError {
  constructor(statusCode: number, message: string) {
    super(`Pago API returned a server error: ${statusCode} - ${message}`);
    this.name = "PagoServerError";
  }
}

export class PagoClientError<T = unknown> extends PagoError {
  constructor(
    public readonly statusCode: number,
    public readonly error: T,
  ) {
    super(`Pago API returned an error: ${statusCode} - ${JSON.stringify(error)}`);
    this.name = "PagoClientError";
  }
}

export class PagoRateLimitError extends PagoClientError {
  constructor(
    public readonly statusCode: 429,
    public readonly retryAfter: number | null = null,
  ) {
    super(statusCode, "Rate limit exceeded");
    this.name = "PagoRateLimitError";
  }
}

type PathParams = Record<string, string | number | boolean>;
type QueryParamValue =
  | string
  | string[]
  | number
  | number[]
  | boolean
  | boolean[]
  | null
  | undefined;
interface QueryParams {
  [key: string]: QueryParamValue | QueryParams;
}

const buildUrl = (url: string, pathParams?: PathParams, queryParams?: QueryParams): string => {
  // Format URL with path params using string replacement
  let formattedUrl = url;
  if (pathParams) {
    for (const [key, value] of Object.entries(pathParams)) {
      if (value !== null && value !== undefined) {
        formattedUrl = formattedUrl.replace(`{${key}}`, encodeURIComponent(String(value)));
      }
    }
  }

  if (queryParams) {
    const searchParams = new URLSearchParams();
    for (const [key, value] of Object.entries(queryParams)) {
      if (value !== null && value !== undefined) {
        if (Array.isArray(value)) {
          for (const item of value) {
            searchParams.append(key, String(item));
          }
        } else if (typeof value === "object") {
          // Handle deepObject style parameters (e.g., metadata)
          for (const [subKey, subValue] of Object.entries(value)) {
            if (subValue !== null && subValue !== undefined) {
              searchParams.append(`${key}[${subKey}]`, String(subValue));
            }
          }
        } else {
          searchParams.append(key, String(value));
        }
      }
    }
    const queryString = searchParams.toString();
    if (queryString) {
      formattedUrl = `${formattedUrl}?${queryString}`;
    }
  }

  return formattedUrl;
};

export interface ClientOptions {
  baseUrl: string;
  version: string;
  accessToken: string;
}

export class ClientBase {
  protected readonly options: ClientOptions;

  constructor(options: ClientOptions) {
    this.options = options;
  }

  public buildRequest(
    method: string,
    url: string,
    pathParams?: PathParams,
    queryParams?: QueryParams,
    body?: unknown,
  ): [string, RequestInit] {
    const fullUrl = buildUrl(`${this.options.baseUrl}${url}`, pathParams, queryParams);
    const headers = new Headers({
      "Content-Type": "application/json",
      "Pago-Version": this.options.version,
      Authorization: `Bearer ${this.options.accessToken}`,
    });
    return [
      fullUrl,
      {
        method,
        headers,
        ...(body ? { body: JSON.stringify(body) } : {}),
      },
    ];
  }

  public async sendRequest(request: [string, RequestInit]): Promise<Response> {
    const [fullUrl, requestInit] = request;
    try {
      return await fetch(fullUrl, requestInit);
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      throw new PagoNetworkError(errorMessage);
    }
  }

  public async parseResponse<T>(
    response: Response,
    responseType: "json" | "text" | "none",
    errors?: Record<number, new (...args: any[]) => PagoClientError>,
  ): Promise<T> {
    const statusCode = response.status;

    if (statusCode >= 500 && statusCode < 600) {
      const text = await response.text().catch(() => "");
      throw new PagoServerError(statusCode, text || "Server error");
    }

    if (statusCode >= 400 && statusCode < 500) {
      if (statusCode === 429) {
        const retryAfter = response.headers.get("Retry-After");
        throw new PagoRateLimitError(statusCode, retryAfter ? parseInt(retryAfter, 10) : null);
      }
      if (errors?.[statusCode]) {
        const ErrorClass = errors[statusCode];
        const errorData = await response.json();
        throw new ErrorClass(statusCode, errorData);
      } else {
        const text = await response.text().catch(() => "");
        throw new PagoClientError(statusCode, text || "Client error");
      }
    }

    if (responseType === "json") {
      return (await response.json()) as T;
    }
    if (responseType === "text") {
      return (await response.text()) as unknown as T;
    }

    return undefined as unknown as T;
  }
}
